const wd = sim.worldData;
const S = wd.__feel || (wd.__feel = { held: 0, pulse: 0, lo: 1, ro: 1, mo: 0 });
const mx = (typeof wd.mouse_x === 'number') ? wd.mouse_x : 256;
const my = (typeof wd.mouse_y === 'number') ? wd.mouse_y : 256;
const px = (mx - 256) / 256;
const py = (256 - my) / 256;
const down = !!wd.mouse_down;
// held eases in while the button is down (the reach), out on release
S.held = down ? Math.min(1, S.held + dt * 3.5) : Math.max(0, S.held - dt * 3.5);
// pulse spikes on the press edge, then fades
const pressed = sim.edge('feelclick', down);
if (pressed) S.pulse = 1;
S.pulse = Math.max(0, S.pulse - dt * 1.8);
// which part is under the pointer — 1 left eye, 2 right eye, 3 mouth
const dL = Math.hypot(px + 0.205, py - 0.36);
const dR = Math.hypot(px - 0.205, py - 0.36);
const dM = Math.hypot(px - 0.0, py - 0.055);
let sel = 0, best = 0.17;
if (dL < best) { best = dL; sel = 1; }
if (dR < best) { best = dR; sel = 2; }
if (dM < best) { best = dM; sel = 3; }
// a click toggles the part it lands on (open/close eye or mouth)
if (pressed) {
  if (sel === 1) S.lo = 1 - S.lo;
  else if (sel === 2) S.ro = 1 - S.ro;
  else if (sel === 3) S.mo = 1 - S.mo;
}
wd.gpuUniforms = [px, py, S.held, S.pulse, S.lo, S.ro, S.mo, sel];
